arguments.file_text:
@page "/settings"
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <nav class="settings-sidebar" role="tablist" aria-label="Settings sections">
        @foreach (var section in _sections)
        {
            <button class="settings-nav-item @(section == _activeSection ? "active" : "")"
                    role="tab"
                    aria-selected="@(section == _activeSection)"
                    @onclick="() => _activeSection = section">
                <span class="settings-nav-icon">@GetIcon(section)</span>
                <span>@section</span>
            </button>
        }
    </nav>

    <section class="settings-content" role="tabpanel">
        <h2 class="settings-section-title">@_activeSection</h2>

        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection />
                break;
            case "Notifications":
                <NotificationsSection />
                break;
            case "Security":
                <SecuritySection />
                break;
            case "Appearance":
                <AppearanceSection />
                break;
        }
    </section>
</div>

@code {
    private readonly string[] _sections = ["Profile", "Notifications", "Security", "Appearance"];
    private string _activeSection = "Profile";

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

.settings-dashboard {
    display: flex;
    gap: 2rem;
    max-width: 1100px;
    margin: 0 auto;
}

.settings-sidebar {
    display: flex;
    flex-direction: column;
    min-width: 200px;
    gap: 0.25rem;
    padding: 0.5rem 0;
    border-right: 1px solid #dee2e6;
}

.settings-nav-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1rem;
    background: none;
    border: none;
    border-radius: 0.5rem;
    cursor: pointer;
    font-size: 0.95rem;
    color: #495057;
    text-align: left;
    transition: background-color 0.15s, color 0.15s;
}

.settings-nav-item:hover {
    background-color: #f1f3f5;
}

.settings-nav-item.active {
    background-color: #e7f5ff;
    color: #1971c2;
    font-weight: 600;
}

.settings-nav-icon {
    font-size: 1.2rem;
}

.settings-content {
    flex: 1;
    min-width: 0;
    padding: 0.5rem 0;
}

.settings-section-title {
    margin-bottom: 1.5rem;
    font-size: 1.5rem;
    font-weight: 600;
}

@using sv_23258b44d71b4ee3926dd5a0883ad178.Services
@inject ISettingsService SettingsService

@if (_profile is null)
{
    <p>Loading profile…</p>
}
else
{
    <div class="profile-section">
        <div class="avatar-area">
            <img src="@_avatarUrl" alt="Avatar preview" class="avatar-preview" />
            <div class="form-group">
                <label for="avatarUrl">Avatar URL</label>
                <input id="avatarUrl" type="url" class="form-control" @bind="_avatarUrl" />
            </div>
        </div>

        <div class="form-group">
            <label for="displayName">Display Name</label>
            <input id="displayName" type="text" class="form-control" @bind="_displayName" />
        </div>

        <div class="form-group">
            <label for="email">Email</label>
            <input id="email" type="email" class="form-control" @bind="_email" />
        </div>

        <div class="form-group">
            <label for="bio">Bio</label>
            <textarea id="bio" class="form-control" rows="4" @bind="_bio"></textarea>
        </div>

        <div class="button-row">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save Changes")
            </button>
            <button class="btn btn-outline-secondary" @onclick="DiscardChanges">
                Discard Changes
            </button>
        </div>

        @if (_toastMessage is not null)
        {
            <div class="toast-message @_toastClass">@_toastMessage</div>
        }
    </div>
}

@code {
    private UserProfile? _profile;
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private bool _saving;
    private string? _toastMessage;
    private string _toastClass = "";

    protected override async Task OnInitializedAsync()
    {
        _profile = await SettingsService.GetProfileAsync();
        PopulateFields(_profile);
    }

    private void PopulateFields(UserProfile p)
    {
        _displayName = p.DisplayName;
        _email = p.Email;
        _avatarUrl = p.AvatarUrl;
        _bio = p.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(updated);
        _profile = updated;
        _saving = false;
        await ShowToast("Profile saved successfully!", "toast-success");
    }

    private void DiscardChanges()
    {
        if (_profile is not null)
            PopulateFields(_profile);
    }

    private async Task ShowToast(string message, string cssClass)
    {
        _toastMessage = message;
        _toastClass = cssClass;
        StateHasChanged();
        await Task.Delay(3000);
        _toastMessage = null;
    }
}

.profile-section {
    display: flex;
    flex-direction: column;
    gap: 1.25rem;
}

.avatar-area {
    display: flex;
    align-items: flex-start;
    gap: 1.5rem;
}

.avatar-preview {
    width: 96px;
    height: 96px;
    border-radius: 50%;
    object-fit: cover;
    border: 2px solid #dee2e6;
    flex-shrink: 0;
}

.avatar-area .form-group {
    flex: 1;
}

.form-group {
    display: flex;
    flex-direction: column;
    gap: 0.35rem;
}

.form-group label {
    font-weight: 600;
    font-size: 0.875rem;
    color: #495057;
}

.button-row {
    display: flex;
    gap: 0.75rem;
    margin-top: 0.5rem;
}

.toast-message {
    margin-top: 0.75rem;
    padding: 0.75rem 1rem;
    border-radius: 0.375rem;
    font-size: 0.9rem;
    animation: toast-fade 0.3s ease-in;
}

.toast-success {
    background-color: #d3f9d8;
    color: #2b8a3e;
    border: 1px solid #b2f2bb;
}

@keyframes toast-fade {
    from { opacity: 0; transform: translateY(-4px); }
    to { opacity: 1; transform: translateY(0); }
}

@using sv_23258b44d71b4ee3926dd5a0883ad178.Services
@inject ISettingsService SettingsService

@if (_prefs is null)
{
    <p>Loading notification preferences…</p>
}
else
{
    <div class="notifications-section">
        <div class="toggle-group">
            <label class="toggle-row">
                <span>Email Notifications</span>
                <input type="checkbox" class="form-check-input" @bind="_emailNotifications" />
            </label>
            <label class="toggle-row">
                <span>Push Notifications</span>
                <input type="checkbox" class="form-check-input" @bind="_pushNotifications" />
            </label>
            <label class="toggle-row">
                <span>Weekly Digest</span>
                <input type="checkbox" class="form-check-input" @bind="_weeklyDigest" />
            </label>
        </div>

        <div class="channels-section">
            <h5>Muted Channels</h5>
            <p class="text-muted small">Select channels to mute.</p>
            <div class="channel-list">
                @foreach (var channel in _allChannels)
                {
                    <label class="channel-item">
                        <input type="checkbox"
                               class="form-check-input"
                               checked="@_mutedSet.Contains(channel)"
                               @onchange="e => ToggleMute(channel, (bool)e.Value!)" />
                        <span>#@channel</span>
                    </label>
                }
            </div>
        </div>

        <div class="button-row">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save Preferences")
            </button>
        </div>

        @if (_toastMessage is not null)
        {
            <div class="toast-message toast-success">@_toastMessage</div>
        }
    </div>
}

@code {
    private NotificationPrefs? _prefs;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private readonly List<string> _allChannels = ["announcements", "random", "off-topic", "watercooler", "design"];
    private HashSet<string> _mutedSet = new();
    private bool _saving;
    private string? _toastMessage;

    protected override async Task OnInitializedAsync()
    {
        _prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = _prefs.EmailNotifications;
        _pushNotifications = _prefs.PushNotifications;
        _weeklyDigest = _prefs.WeeklyDigest;
        _mutedSet = new HashSet<string>(_prefs.MutedChannels);
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedSet.Add(channel);
        else
            _mutedSet.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var updated = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, _mutedSet.ToList());
        await SettingsService.SaveNotificationPrefsAsync(updated);
        _prefs = updated;
        _saving = false;
        _toastMessage = "Notification preferences saved!";
        StateHasChanged();
        await Task.Delay(3000);
        _toastMessage = null;
    }
}

.notifications-section {
    display: flex;
    flex-direction: column;
    gap: 1.5rem;
}

.toggle-group {
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
}

.toggle-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border-radius: 0.5rem;
    cursor: pointer;
    font-weight: 500;
}

.toggle-row:hover {
    background: #e9ecef;
}

.channels-section h5 {
    margin-bottom: 0.25rem;
}

.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.channel-item {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.5rem 0.75rem;
    border-radius: 0.375rem;
    cursor: pointer;
}

.channel-item:hover {
    background: #f1f3f5;
}

.button-row {
    display: flex;
    gap: 0.75rem;
}

.toast-message {
    margin-top: 0.75rem;
    padding: 0.75rem 1rem;
    border-radius: 0.375rem;
    font-size: 0.9rem;
}

.toast-success {
    background-color: #d3f9d8;
    color: #2b8a3e;
    border: 1px solid #b2f2bb;
}

@using sv_23258b44d71b4ee3926dd5a0883ad178.Services
@inject ISettingsService SettingsService

@if (_security is null)
{
    <p>Loading security settings…</p>
}
else
{
    <div class="security-section">
        <!-- Change Password Panel -->
        <div class="expandable-panel">
            <button class="panel-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                <span>🔑 Change Password</span>
                <span class="chevron @(_passwordPanelOpen ? "open" : "")">▸</span>
            </button>
            @if (_passwordPanelOpen)
            {
                <div class="panel-body">
                    <div class="form-group">
                        <label for="currentPassword">Current Password</label>
                        <input id="currentPassword" type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="form-group">
                        <label for="newPassword">New Password</label>
                        <input id="newPassword" type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="form-group">
                        <label for="confirmPassword">Confirm Password</label>
                        <input id="confirmPassword" type="password" class="form-control" @bind="_confirmPassword" />
                    </div>

                    @if (_passwordError is not null)
                    {
                        <div class="alert alert-danger">@_passwordError</div>
                    }
                    @if (_passwordSuccess is not null)
                    {
                        <div class="alert alert-success">@_passwordSuccess</div>
                    }

                    <button class="btn btn-primary" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                        @(_changingPassword ? "Updating…" : "Update Password")
                    </button>
                </div>
            }
        </div>

        <!-- Two-Factor Authentication -->
        <div class="tfa-section">
            <div class="tfa-header">
                <div>
                    <h5>Two-Factor Authentication</h5>
                    <span class="status-badge @(_twoFactorEnabled ? "status-enabled" : "status-disabled")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </div>
                <label class="toggle-switch">
                    <input type="checkbox" @bind="_twoFactorEnabled" />
                    <span class="slider"></span>
                </label>
            </div>
            @if (_security.LastPasswordChange.HasValue)
            {
                <p class="text-muted small">Last password change: @_security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")</p>
            }
        </div>

        <!-- Active Sessions -->
        <div class="sessions-section">
            <h5>Active Sessions</h5>
            <table class="table table-striped">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in _security.Sessions)
                    {
                        var isCurrent = session.Id == "session-current";
                        <tr>
                            <td>
                                @session.Device
                                @if (isCurrent)
                                {
                                    <span class="badge bg-success ms-1">Current</span>
                                }
                            </td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (!isCurrent)
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => PromptRevoke(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>

        <!-- Revoke Confirmation Dialog -->
        @if (_sessionToRevoke is not null)
        {
            <div class="modal-backdrop" @onclick="CancelRevoke">
                <div class="confirmation-dialog" @onclick:stopPropagation="true">
                    <h5>Revoke Session</h5>
                    <p>
                        Are you sure you want to revoke the session on
                        <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?
                    </p>
                    <div class="button-row">
                        <button class="btn btn-danger" @onclick="ConfirmRevokeAsync">Revoke</button>
                        <button class="btn btn-outline-secondary" @onclick="CancelRevoke">Cancel</button>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private SecuritySettings? _security;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private string? _passwordSuccess;
    private bool _changingPassword;
    private bool _twoFactorEnabled;
    private ActiveSession? _sessionToRevoke;

    protected override async Task OnInitializedAsync()
    {
        _security = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = _security.TwoFactorEnabled;
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = null;
        _passwordSuccess = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordError = "Current password is required.";
            return;
        }
        if (_newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }

        _changingPassword = true;
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _security = await SettingsService.GetSecuritySettingsAsync();
        _changingPassword = false;
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _passwordSuccess = "Password updated successfully!";
    }

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _security = await SettingsService.GetSecuritySettingsAsync();
        _sessionToRevoke = null;
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalHours < 1) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalDays < 1) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

