                        <input id="confirmPassword" type="password" class="form-control" @bind="_confirmPassword" />
                    </div>

                    @if (_passwordError is not null)
                    {
                        <div class="alert alert-danger">@_passwordError</div>
                    }
                    @if (_passwordSuccess is not null)
                    {
                        <div class="alert alert-success">@_passwordSuccess</div>
                    }

                    <button class="btn btn-primary" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                        @(_changingPassword ? "Updating…" : "Update Password")
                    </button>
                </div>
            }
        </div>

        <!-- Two-Factor Authentication -->
        <div class="tfa-section">
            <div class="tfa-header">
                <div>
                    <h5>Two-Factor Authentication</h5>
                    <span class="status-badge @(_twoFactorEnabled ? "status-enabled" : "status-disabled")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </div>
                <label class="toggle-switch">
                    <input type="checkbox" @bind="_twoFactorEnabled" />
                    <span class="slider"></span>
                </label>
            </div>
            @if (_security.LastPasswordChange.HasValue)
            {
                <p class="text-muted small">Last password change: @_security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")</p>
            }
        </div>

        <!-- Active Sessions -->
        <div class="sessions-section">
            <h5>Active Sessions</h5>
            <table class="table table-striped">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in _security.Sessions)
                    {
                        var isCurrent = session.Id == "session-current";
                        <tr>
                            <td>
                                @session.Device
                                @if (isCurrent)
                                {
                                    <span class="badge bg-success ms-1">Current</span>
                                }
                            </td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (!isCurrent)
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => PromptRevoke(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>

        <!-- Revoke Confirmation Dialog -->
        @if (_sessionToRevoke is not null)
        {
            <div class="modal-backdrop" @onclick="CancelRevoke">
                <div class="confirmation-dialog" @onclick:stopPropagation="true">
                    <h5>Revoke Session</h5>
                    <p>
                        Are you sure you want to revoke the session on
                        <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?
                    </p>
                    <div class="button-row">
                        <button class="btn btn-danger" @onclick="ConfirmRevokeAsync">Revoke</button>
                        <button class="btn btn-outline-secondary" @onclick="CancelRevoke">Cancel</button>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private SecuritySettings? _security;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private string? _passwordSuccess;
    private bool _changingPassword;
    private bool _twoFactorEnabled;
    private ActiveSession? _sessionToRevoke;

    protected override async Task OnInitializedAsync()
    {
        _security = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = _security.TwoFactorEnabled;
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = null;
        _passwordSuccess = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordError = "Current password is required.";
            return;
        }
        if (_newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }

        _changingPassword = true;
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _security = await SettingsService.GetSecuritySettingsAsync();
        _changingPassword = false;
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _passwordSuccess = "Password updated successfully!";
    }

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _security = await SettingsService.GetSecuritySettingsAsync();
        _sessionToRevoke = null;
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalHours < 1) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalDays < 1) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

