                    <label class="channel-item">
                        <input type="checkbox"
                               class="form-check-input"
                               checked="@_mutedSet.Contains(channel)"
                               @onchange="e => ToggleMute(channel, (bool)e.Value!)" />
                        <span>#@channel</span>
                    </label>
                }
            </div>
        </div>

        <div class="button-row">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save Preferences")
            </button>
        </div>

        @if (_toastMessage is not null)
        {
            <div class="toast-message toast-success">@_toastMessage</div>
        }
    </div>
}

@code {
    private NotificationPrefs? _prefs;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private readonly List<string> _allChannels = ["announcements", "random", "off-topic", "watercooler", "design"];
    private HashSet<string> _mutedSet = new();
    private bool _saving;
    private string? _toastMessage;

    protected override async Task OnInitializedAsync()
    {
        _prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = _prefs.EmailNotifications;
        _pushNotifications = _prefs.PushNotifications;
        _weeklyDigest = _prefs.WeeklyDigest;
        _mutedSet = new HashSet<string>(_prefs.MutedChannels);
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedSet.Add(channel);
        else
            _mutedSet.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var updated = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, _mutedSet.ToList());
        await SettingsService.SaveNotificationPrefsAsync(updated);
        _prefs = updated;
        _saving = false;
        _toastMessage = "Notification preferences saved!";
        StateHasChanged();
        await Task.Delay(3000);
        _toastMessage = null;
    }
}
