                <span>Some descriptive text appears here in your chosen style.</span>
            </div>
        </div>

        <div class="button-row">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save")
            </button>
