toolArgs.file_text:
@using sv_23258b44d71b4ee3926dd5a0883ad178.Services
@inject ISettingsService SettingsService

@if (_profile is null)
{
    <p>Loading profile…</p>
}
else
{
    <div class="profile-section">
        <div class="avatar-area">
            <img src="@_avatarUrl" alt="Avatar preview" class="avatar-preview" />
            <div class="form-group">
                <label for="avatarUrl">Avatar URL</label>
                <input id="avatarUrl" type="url" class="form-control" @bind="_avatarUrl" />
            </div>
        </div>

        <div class="form-group">
            <label for="displayName">Display Name</label>
            <input id="displayName" type="text" class="form-control" @bind="_displayName" />
        </div>

        <div class="form-group">
            <label for="email">Email</label>
            <input id="email" type="email" class="form-control" @bind="_email" />
        </div>

        <div class="form-group">
            <label for="bio">Bio</label>
            <textarea id="bio" class="form-control" rows="4" @bind="_bio"></textarea>
        </div>

        <div class="button-row">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save Changes")
            </button>
            <button class="btn btn-outline-secondary" @onclick="DiscardChanges">
                Discard Changes
            </button>
        </div>

        @if (_toastMessage is not null)
        {
            <div class="toast-message @_toastClass">@_toastMessage</div>
        }
    </div>
}

@code {
    private UserProfile? _profile;
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private bool _saving;
    private string? _toastMessage;
    private string _toastClass = "";

    protected override async Task OnInitializedAsync()
    {
        _profile = await SettingsService.GetProfileAsync();
        PopulateFields(_profile);
    }

    private void PopulateFields(UserProfile p)
    {
        _displayName = p.DisplayName;
        _email = p.Email;
        _avatarUrl = p.AvatarUrl;
        _bio = p.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(updated);
        _profile = updated;
        _saving = false;
        await ShowToast("Profile saved successfully!", "toast-success");
    }

    private void DiscardChanges()
    {
        if (_profile is not null)
            PopulateFields(_profile);
    }

    private async Task ShowToast(string message, string cssClass)
    {
        _toastMessage = message;
        _toastClass = cssClass;
        StateHasChanged();
        await Task.Delay(3000);
        _toastMessage = null;
    }
}

