toolArgs.file_text:
.profile-section {
    display: flex;
    flex-direction: column;
    gap: 1.25rem;
}

.avatar-area {
    display: flex;
    align-items: flex-start;
    gap: 1.5rem;
}

.avatar-preview {
    width: 96px;
    height: 96px;
    border-radius: 50%;
    object-fit: cover;
    border: 2px solid #dee2e6;
    flex-shrink: 0;
}

.avatar-area .form-group {
    flex: 1;
}

.form-group {
    display: flex;
    flex-direction: column;
    gap: 0.35rem;
}

.form-group label {
    font-weight: 600;
    font-size: 0.875rem;
    color: #495057;
}

.button-row {
    display: flex;
    gap: 0.75rem;
    margin-top: 0.5rem;
}

.toast-message {
    margin-top: 0.75rem;
    padding: 0.75rem 1rem;
    border-radius: 0.375rem;
    font-size: 0.9rem;
    animation: toast-fade 0.3s ease-in;
}

.toast-success {
    background-color: #d3f9d8;
    color: #2b8a3e;
    border: 1px solid #b2f2bb;
}

@keyframes toast-fade {
    from { opacity: 0; transform: translateY(-4px); }
    to { opacity: 1; transform: translateY(0); }
}

