toolArgs.file_text:
.security-section {
    display: flex;
    flex-direction: column;
    gap: 1.5rem;
}

/* Expandable Panel */
.expandable-panel {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
}

.panel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    width: 100%;
    padding: 1rem 1.25rem;
    background: #f8f9fa;
    border: none;
    cursor: pointer;
    font-size: 1rem;
    font-weight: 600;
}

.panel-header:hover {
    background: #e9ecef;
}

.chevron {
    transition: transform 0.2s;
}

.chevron.open {
    transform: rotate(90deg);
}

.panel-body {
    padding: 1.25rem;
    display: flex;
    flex-direction: column;
    gap: 1rem;
    border-top: 1px solid #dee2e6;
}

.form-group {
    display: flex;
    flex-direction: column;
    gap: 0.35rem;
}

.form-group label {
    font-weight: 600;
    font-size: 0.875rem;
    color: #495057;
}

/* Two-Factor */
.tfa-section {
    padding: 1rem 1.25rem;
    background: #f8f9fa;
    border-radius: 0.5rem;
}

.tfa-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.tfa-header h5 {
    margin-bottom: 0.25rem;
}

.status-badge {
    display: inline-block;
    padding: 0.15rem 0.5rem;
    border-radius: 1rem;
    font-size: 0.75rem;
    font-weight: 600;
}

.status-enabled {
    background: #d3f9d8;
    color: #2b8a3e;
}

.status-disabled {
    background: #ffe3e3;
    color: #c92a2a;
}

.toggle-switch {
    position: relative;
    display: inline-block;
    width: 48px;
    height: 26px;
}

.toggle-switch input {
    opacity: 0;
    width: 0;
    height: 0;
}

.slider {
    position: absolute;
    cursor: pointer;
    inset: 0;
    background-color: #ced4da;
    border-radius: 26px;
    transition: background-color 0.2s;
}

.slider::before {
    content: "";
    position: absolute;
    height: 20px;
    width: 20px;
    left: 3px;
    bottom: 3px;
    background: white;
    border-radius: 50%;
    transition: transform 0.2s;
}

.toggle-switch input:checked + .slider {
    background-color: #1971c2;
}

.toggle-switch input:checked + .slider::before {
    transform: translateX(22px);
}

/* Sessions */
.sessions-section h5 {
    margin-bottom: 0.75rem;
}

/* Confirmation Dialog */
.modal-backdrop {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.4);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1050;
}

.confirmation-dialog {
    background: white;
    border-radius: 0.75rem;
    padding: 1.5rem;
    max-width: 420px;
    width: 90%;
    box-shadow: 0 10px 40px rgba(0, 0, 0, 0.2);
}

.confirmation-dialog h5 {
    margin-bottom: 0.75rem;
}

.button-row {
    display: flex;
    gap: 0.75rem;
    margin-top: 1rem;
}

