toolArgs.file_text:
@using sv_23258b44d71b4ee3926dd5a0883ad178.Services
@inject ISettingsService SettingsService

@if (_settings is null)
{
    <p>Loading appearance settings…</p>
}
else
{
    <div class="appearance-section">
        <!-- Theme -->
        <fieldset class="option-group">
            <legend>Theme</legend>
            <div class="radio-group">
                @foreach (var theme in _themes)
                {
                    <label class="radio-card @(_theme == theme ? "selected" : "")">
                        <input type="radio" name="theme" value="@theme"
                               checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <span>@theme</span>
                    </label>
                }
            </div>
        </fieldset>

        <!-- Font Size -->
        <fieldset class="option-group">
            <legend>Font Size</legend>
            <div class="radio-group">
                @foreach (var size in _fontSizes)
                {
                    <label class="radio-card @(_fontSize == size ? "selected" : "")">
                        <input type="radio" name="fontSize" value="@size"
                               checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <span>@size</span>
                    </label>
                }
            </div>
        </fieldset>

        <!-- Language -->
        <div class="form-group">
            <label for="language">Language</label>
            <select id="language" class="form-select" @bind="_language">
                @foreach (var lang in _languages)
                {
                    <option value="@lang">@lang</option>
                }
            </select>
        </div>

        <!-- Compact Mode -->
        <label class="toggle-row">
            <span>Compact Mode</span>
            <input type="checkbox" class="form-check-input" @bind="_compactMode" />
        </label>

        <!-- Live Preview -->
        <div class="live-preview @GetPreviewClasses()">
            <h6>Live Preview</h6>
            <p>This is how your content will look with the selected settings.</p>
            <div class="preview-card">
                <strong>Sample Card</strong>
                <span>Some descriptive text appears here in your chosen style.</span>
            </div>
        </div>

        <div class="button-row">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save")
            </button>
        </div>

        @if (_toastMessage is not null)
        {
            <div class="toast-message toast-success">@_toastMessage</div>
        }
    </div>
}

@code {
    private AppearanceSettings? _settings;
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _saving;
    private string? _toastMessage;

    private readonly string[] _themes = ["Light", "Dark", "System"];
    private readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        _settings = await SettingsService.GetAppearanceAsync();
        _theme = _settings.Theme;
        _fontSize = _settings.FontSize;
        _language = _settings.Language;
        _compactMode = _settings.CompactMode;
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add($"preview-theme-{_theme.ToLowerInvariant()}");
        classes.Add($"preview-font-{_fontSize.ToLowerInvariant()}");
        if (_compactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(updated);
        _settings = updated;
        _saving = false;
        _toastMessage = "Appearance saved!";
        StateHasChanged();
        await Task.Delay(3000);
        _toastMessage = null;
    }
}

