toolArgs.file_text:
.appearance-section {
    display: flex;
    flex-direction: column;
    gap: 1.5rem;
}

.option-group {
    border: none;
    padding: 0;
    margin: 0;
}

.option-group legend {
    font-weight: 600;
    font-size: 0.95rem;
    margin-bottom: 0.5rem;
    color: #495057;
}

.radio-group {
    display: flex;
    gap: 0.75rem;
}

.radio-card {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.6rem 1.25rem;
    border: 2px solid #dee2e6;
    border-radius: 0.5rem;
    cursor: pointer;
    transition: border-color 0.15s, background-color 0.15s;
    font-weight: 500;
}

.radio-card:hover {
    border-color: #a5d8ff;
}

.radio-card.selected {
    border-color: #1971c2;
    background-color: #e7f5ff;
}

.radio-card input[type="radio"] {
    accent-color: #1971c2;
}

.form-group {
    display: flex;
    flex-direction: column;
    gap: 0.35rem;
    max-width: 280px;
}

.form-group label {
    font-weight: 600;
    font-size: 0.875rem;
    color: #495057;
}

.toggle-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border-radius: 0.5rem;
    cursor: pointer;
    font-weight: 500;
    max-width: 340px;
}

.toggle-row:hover {
    background: #e9ecef;
}

/* Live Preview */
.live-preview {
    border: 1px solid #dee2e6;
    border-radius: 0.75rem;
    padding: 1.25rem;
    transition: all 0.3s ease;
}

.live-preview h6 {
    margin-bottom: 0.5rem;
}

.preview-card {
    margin-top: 0.75rem;
    padding: 0.75rem 1rem;
    border-radius: 0.375rem;
    border: 1px solid #dee2e6;
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
}

/* Theme variants */
.preview-theme-light {
    background: #ffffff;
    color: #212529;
}

.preview-theme-light .preview-card {
    background: #f8f9fa;
}

.preview-theme-dark {
    background: #1a1b1e;
    color: #c1c2c5;
    border-color: #373a40;
}

.preview-theme-dark .preview-card {
    background: #25262b;
    border-color: #373a40;
}

.preview-theme-system {
    background: linear-gradient(135deg, #ffffff 50%, #1a1b1e 50%);
    color: #495057;
}

.preview-theme-system .preview-card {
    background: #e9ecef;
}

/* Font size variants */
.preview-font-small {
    font-size: 0.8rem;
}

.preview-font-medium {
    font-size: 1rem;
}

.preview-font-large {
    font-size: 1.2rem;
}

/* Compact mode */
.preview-compact {
    padding: 0.75rem;
    line-height: 1.3;
}

.preview-compact .preview-card {
    padding: 0.4rem 0.75rem;
    margin-top: 0.4rem;
}

.button-row {
    display: flex;
    gap: 0.75rem;
}

.toast-message {
    margin-top: 0.75rem;
    padding: 0.75rem 1rem;
    border-radius: 0.375rem;
    font-size: 0.9rem;
}

.toast-success {
    background-color: #d3f9d8;
    color: #2b8a3e;
    border: 1px solid #b2f2bb;
}

